refsection.programlisting:
// load the database containing the GDP for 25 countries in the OECD over the period 1963-2003
load(GROCERDIR+'/data/gdpan_oecd.dat');
// retrieve the names of all variables in database
listvar=dblist(GROCERDIR+'/macros/grocer/db/gdpan_oecd.dat')
res = Maddala_Wu('log('+listvar+')','pmax=4','t_order=0')
// provides the Maddala and Wu test for all variables in the database, taken in logarithm,
// with a constant but not trend ('t_order=0'), the Lag order to be determined by the programm,
// the maximum number of lags set to 4 (arg 'pmax=4').
